import AOS from "aos";

const About = () => {
  return (
    <div id="about">
      <div class="p-5 mb-4 bg-light rounded-3 text-center">
        <div class="container-fluid py-5">
          <h1 class="display-5 fw-bold">Web Services for Small Business Owners</h1>
          <p class="container col-md-8 fs-4 text-center">
            Helping small business owners build their online presents with their professionally build website
          </p>
          <button class="btn btn-primary btn-lg" type="button">
            Example button
          </button>
        </div>
      </div>
    </div>
  );
};

export default About;
